// Fetch ALL videos from your YouTube channel with full snippet data
// Handles pagination automatically (works for any channel size)

const credentialType = 'googleOAuth2Api';

// Step 1: Get the uploads playlist ID for your channel
const channelResponse = await this.helpers.httpRequestWithAuthentication.call(
  this,
  credentialType,
  {
    method: 'GET',
    url: 'https://www.googleapis.com/youtube/v3/channels',
    qs: { part: 'contentDetails', mine: 'true' },
    json: true,
  }
);

if (!channelResponse.items || channelResponse.items.length === 0) {
  throw new Error('No YouTube channel found for this account');
}

const uploadsPlaylistId = channelResponse.items[0].contentDetails.relatedPlaylists.uploads;

// Step 2: Get ALL video IDs from the uploads playlist (with pagination)
const allVideoIds = [];
let nextPageToken = '';

do {
  const qs = {
    part: 'snippet',
    playlistId: uploadsPlaylistId,
    maxResults: '50',
  };
  if (nextPageToken) qs.pageToken = nextPageToken;

  const playlistResponse = await this.helpers.httpRequestWithAuthentication.call(
    this,
    credentialType,
    {
      method: 'GET',
      url: 'https://www.googleapis.com/youtube/v3/playlistItems',
      qs,
      json: true,
    }
  );

  for (const item of playlistResponse.items) {
    allVideoIds.push(item.snippet.resourceId.videoId);
  }
  nextPageToken = playlistResponse.nextPageToken || '';
} while (nextPageToken);

// Step 3: Get full video details in batches of 50
const allVideos = [];

for (let i = 0; i < allVideoIds.length; i += 50) {
  const batchIds = allVideoIds.slice(i, i + 50).join(',');

  const videosResponse = await this.helpers.httpRequestWithAuthentication.call(
    this,
    credentialType,
    {
      method: 'GET',
      url: 'https://www.googleapis.com/youtube/v3/videos',
      qs: { part: 'snippet', id: batchIds },
      json: true,
    }
  );

  for (const video of videosResponse.items) {
    allVideos.push({
      json: {
        videoId: video.id,
        title: video.snippet.title,
        description: video.snippet.description || '',
        snippet: {
          title: video.snippet.title,
          description: video.snippet.description || '',
          categoryId: video.snippet.categoryId,
          tags: video.snippet.tags || [],
          defaultLanguage: video.snippet.defaultLanguage || '',
          defaultAudioLanguage: video.snippet.defaultAudioLanguage || '',
        },
      },
    });
  }
}

return allVideos;

// Apply description modifications based on Config settings
// Supports: append, prepend, replace
// Safety: idempotency check, 5000 char limit

const config = $('Config').first().json;
const items = $input.all();
const results = [];

for (const item of items) {
  const video = item.json;
  const currentDesc = video.description || '';
  let newDesc = currentDesc;
  let skipped = false;
  let skipReason = '';

  // Idempotency: skip if description already contains marker text
  if (config.skip_if_contains && currentDesc.includes(config.skip_if_contains)) {
    skipped = true;
    skipReason = 'already contains marker text';
  }

  if (!skipped) {
    switch (config.operation) {
      case 'append':
        newDesc = currentDesc + config.text_to_add;
        break;
      case 'prepend':
        newDesc = config.text_to_add + currentDesc;
        break;
      case 'replace':
        if (config.find_text) {
          newDesc = currentDesc.replaceAll(config.find_text, config.replace_text);
        }
        break;
    }

    // YouTube description limit: 5000 characters
    if (newDesc.length > 5000) {
      skipped = true;
      skipReason = `description would be ${newDesc.length} chars (limit: 5000)`;
      newDesc = currentDesc;
    }
  }

  results.push({
    json: {
      videoId: video.videoId,
      title: video.title,
      currentDescription: currentDesc,
      newDescription: newDesc,
      changed: currentDesc !== newDesc,
      skipped,
      skipReason,
      snippet: {
        ...video.snippet,
        description: newDesc,
      },
    },
  });
}

return results;

// Build a preview report for dry run mode

const items = $input.all();
const config = $('Config').first().json;
const changed = items.filter(i => i.json.changed);
const skipped = items.filter(i => i.json.skipped);
const unchanged = items.filter(i => !i.json.changed && !i.json.skipped);

let report = `<b>DRY RUN REPORT</b>\n\n`;
report += `<b>Operation:</b> ${config.operation}\n`;
report += `<b>Total videos:</b> ${items.length}\n`;
report += `<b>Would change:</b> ${changed.length}\n`;
report += `<b>Skipped:</b> ${skipped.length}\n`;
report += `<b>Unchanged:</b> ${unchanged.length}\n\n`;

if (skipped.length > 0) {
  report += `<b>--- Skipped Videos ---</b>\n`;
  for (const item of skipped.slice(0, 5)) {
    report += `- ${item.json.title} (${item.json.skipReason})\n`;
  }
  if (skipped.length > 5) report += `...and ${skipped.length - 5} more\n`;
  report += `\n`;
}

if (changed.length > 0) {
  report += `<b>--- First 5 Changes ---</b>\n\n`;
  for (const item of changed.slice(0, 5)) {
    const before = item.json.currentDescription.substring(0, 80);
    const after = item.json.newDescription.substring(0, 80);
    report += `<b>${item.json.title}</b>\n`;
    report += `Before: ${before}...\n`;
    report += `After: ${after}...\n\n`;
  }
}

report += `\nSet mode to "update" and run again to apply changes.`;

return [{ json: { report } }];

// Filter to only changed videos and apply batch size limit

const config = $('Config').first().json;
const items = $input.all();

// Filter: only videos where description actually changed
const changed = items.filter(i => i.json.changed);

// Apply batch size limit (quota safety)
const batchSize = parseInt(config.batch_size) || 190;
const limited = changed.slice(0, batchSize);

// Add progress tracking metadata
return limited.map((item, index) => ({
  json: {
    ...item.json,
    _index: index + 1,
    _total: limited.length,
    _originalTotal: changed.length,
  },
}));

// Generate final summary after all updates are done

const items = $input.all();
const totalUpdated = items.length;

const config = $('Config').first().json;

let report = `<b>UPDATE COMPLETE</b>\n\n`;
report += `<b>Videos updated:</b> ${totalUpdated}\n`;
report += `<b>Operation:</b> ${config.operation}\n`;
report += `<b>Quota used:</b> ~${totalUpdated * 50 + 10} / 10,000 units\n\n`;
report += `Check YouTube Studio to verify the changes.`;

return [{ json: { report } }];
